import { Component, OnInit, VERSION } from '@angular/core';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { EChartsOption } from 'echarts';

export class Counrty {
  countryCode: string;
  name: string;
  constructor(countryCode: string, name: string) {
    this.countryCode = countryCode;
    this.name = name;
  }
}
export class Border {
  commonName: string;
  officialName: string;
  countryCode: string;
  region: string;
  borders: null;
  constructor(commonName: string, officialName: string, countryCode: string, region: string, borders: null) {
    this.commonName = commonName;
    this.officialName = officialName;
    this.countryCode = countryCode;
    this.region = region;
    this.borders = borders;
  }
}
class Rcmd_Country extends Counrty {
  holidays: number;
  constructor(countryCode: string, name: string, holidays: number) {
    super(countryCode, name);
    this.holidays = holidays;
  }
}
