  year = 2022;
  changeYear() {
    if (this.year > 2122) this.year = 2122;
    if (this.year < 1922) this.year = 1922;
  }

  rcmd_country: Rcmd_Country[] = [];
  // searchNeighbour(): Search Neighbors and count their holiday numbers separately
  // Results: B_CT, holidays.
  searchNeighbour() {
    // get border countries data
    var B_CT: Border[] = [];
    var holidays: number[] = [];
    var rcmd: Rcmd_Country[] = [];

    var temps: String = this.c_selected.toString();
    var api =
      'https://date.nager.at/api/v3/CountryInfo/' +
      temps.substr(temps.length - 3, 2);

    this.http.get<any>(api).subscribe((data) => {
      B_CT = data.borders;
      var cnt = 0;
      var bd_api =
        'https://date.nager.at/api/v3/PublicHolidays/' + this.year + '/';
      for (let j = 0; j < B_CT.length; j++) {
        // to get holiday number
        this.http.get<any>(bd_api + B_CT[j].countryCode).subscribe((result) => {
          if (result == null) holidays.push(0);
          else holidays.push(result.length);
          cnt++;
          // console.log(holidays);
          if (cnt == B_CT.length) {
            // now, has holiday numbers of all border countries
            for (let m = 0; m < 3; m++) {
              var max_hol = -1;
              var max_index = -1;
              for (let n = 0; n < holidays.length; n++) {
                if (holidays[n] > max_hol) {
                  max_hol = holidays[n];
                  max_index = n;
                }
              }
              if (max_index == -1) break;
              var temp_rcmd = new Rcmd_Country(
                B_CT[max_index].countryCode,
                B_CT[max_index].commonName,
                holidays[max_index]
              );
              rcmd.push(temp_rcmd);
              holidays[max_index] = -1;
            }
            this.rcmd_country = rcmd;
            // console.log(this.rcmd_country);
            this.des_show = true;
          }
        });
      }
    });
  }
